changeSet.sql:
UPDATE clinlims.notebook_page SET page_order = 9
WHERE title = 'Storage & Inventory Management'
AND notebook_id IN (SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory');

UPDATE clinlims.notebook_page SET page_order = 10
WHERE title = 'Reporting & Performance Monitoring'
AND notebook_id IN (SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory');

UPDATE clinlims.notebook_page SET page_order = 11
WHERE title = 'Disposal & Archiving'
AND notebook_id IN (SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory');

UPDATE clinlims.notebook_page SET page_order = 8, title = 'Microscopy & Diagnosis'
WHERE title = 'Testing, Staining & Microscopy'
AND notebook_id IN (SELECT id FROM clinlims.notebook WHERE title = 'Pathology Laboratory');

column.value:
{
  "pageDescription": "Cassette Setup - Create cassettes from grossed specimens",
  "dataPoints": {
    "cassetteConfiguration": {
      "numberOfCassettes": {"type": "number", "label": "Number of Cassettes", "required": true, "min": 1},
      "cassettePrefix": {"type": "text", "label": "Cassette ID Prefix", "required": true},
      "cassetteColor": {"type": "choice", "label": "Cassette Color", "options": ["White", "Pink", "Blue", "Green", "Yellow", "Orange", "Lavender", "Tan", "Gray"]}
    },
    "tissueInfo": {
      "tissueType": {"type": "text", "label": "Tissue Type"},
      "tissueOrientation": {"type": "text", "label": "Tissue Orientation"},
      "sectioningNotes": {"type": "textarea", "label": "Sectioning Notes"}
    },
    "staffInfo": {
      "technicianName": {"type": "text", "label": "Technician Name", "required": true},
      "technicianInitials": {"type": "text", "label": "Initials"},
      "cassetteDate": {"type": "date", "label": "Date", "required": true}
    }
  },
  "nextPage": "Block Creation"
}

{
  "pageDescription": "Block Creation - Embed tissue from cassettes into paraffin blocks",
  "dataPoints": {
    "blockConfiguration": {
      "numberOfBlocks": {"type": "number", "label": "Number of Blocks", "required": true, "min": 1},
      "blockPrefix": {"type": "text", "label": "Block ID Prefix", "required": true},
      "embeddingMedium": {"type": "choice", "label": "Embedding Medium", "options": ["Paraffin Wax", "OCT (Frozen)", "Resin", "Celloidin"], "default": "Paraffin Wax"}
    },
    "embeddingDetails": {
      "embeddingTemperature": {"type": "text", "label": "Temperature (C)"},
      "embeddingStation": {"type": "text", "label": "Embedding Station"},
      "embeddingQuality": {"type": "choice", "label": "Embedding Quality", "options": ["Excellent", "Good", "Acceptable", "Poor - Needs Re-embedding"]}
    },
    "orientation": {
      "tissueOrientation": {"type": "text", "label": "Orientation Description"},
      "orientationVerified": {"type": "boolean", "label": "Orientation Verified", "required": true}
    },
    "staffInfo": {
      "technicianName": {"type": "text", "label": "Technician Name", "required": true},
      "blockDate": {"type": "date", "label": "Date", "required": true}
    }
  },
  "nextPage": "Slide Preparation"
}

{
  "pageDescription": "Slide Preparation - Cut sections from blocks and mount on slides",
  "dataPoints": {
    "slideConfiguration": {
      "numberOfSlides": {"type": "number", "label": "Number of Slides", "required": true, "min": 1},
      "slidePrefix": {"type": "text", "label": "Slide ID Prefix", "required": true},
      "slideType": {"type": "choice", "label": "Slide Type", "options": ["Frosted End", "Plain", "Charged/Plus", "Adhesive Coated"], "default": "Frosted End"}
    },
    "microtomy": {
      "sectionThickness": {"type": "number", "label": "Section Thickness (um)", "required": true, "default": 4, "min": 1, "max": 50},
      "microtomeId": {"type": "text", "label": "Microtome ID"},
      "bladeType": {"type": "choice", "label": "Blade Type", "options": ["Disposable Steel", "Tungsten Carbide", "Diamond", "Glass Knife"]},
      "floatationBathTemp": {"type": "text", "label": "Floatation Bath Temp (C)"}
    },
    "quality": {
      "sectionQuality": {"type": "choice", "label": "Section Quality", "options": ["Excellent - No artifacts", "Good - Minor artifacts", "Acceptable - Some artifacts", "Poor - Significant artifacts", "Needs Re-cut"]},
      "coverslipped": {"type": "boolean", "label": "Coverslipped"}
    },
    "staffInfo": {
      "technicianName": {"type": "text", "label": "Technician Name", "required": true},
      "slideDate": {"type": "date", "label": "Date", "required": true}
    }
  },
  "nextPage": "Slide Staining"
}

{
  "pageDescription": "Slide Staining - Apply stains to prepared slides",
  "dataPoints": {
    "routineStaining": {
      "routineStainingCategory": {"type": "choice", "label": "Staining Category", "options": ["Histology", "Cytology", "Hematology", "Microbiology"]},
      "routineStains": {"type": "multiselect", "label": "Routine Stains", "options": ["H&E", "Pap", "Giemsa", "Wright-Giemsa", "Gram", "AFB"]}
    },
    "specialStains": {
      "specialStains": {"type": "multiselect", "label": "Special Stains", "options": ["PAS", "PAS-D", "Masson Trichrome", "Reticulin", "Iron (Prussian Blue)", "Congo Red", "Mucicarmine", "Alcian Blue", "EVG (Elastic)", "AFB", "GMS (Grocott)"]},
      "specialStainIndication": {"type": "text", "label": "Indication"}
    },
    "ihcIcc": {
      "ihcPerformed": {"type": "boolean", "label": "IHC/ICC Performed"},
      "ihcMarkers": {"type": "text", "label": "Markers"},
      "ihcClone": {"type": "text", "label": "Clone"},
      "ihcDilution": {"type": "text", "label": "Dilution"}
    },
    "controls": {
      "positiveControlRun": {"type": "boolean", "label": "Positive Control Run"},
      "negativeControlRun": {"type": "boolean", "label": "Negative Control Run"},
      "controlsAccepted": {"type": "boolean", "label": "Controls Accepted"},
      "stainQualityAdequate": {"type": "boolean", "label": "Stain Quality Adequate"}
    },
    "batchInfo": {
      "batchNumber": {"type": "text", "label": "Batch Number"},
      "batchDate": {"type": "date", "label": "Batch Date"}
    },
    "staffInfo": {
      "technicianName": {"type": "text", "label": "Technician Name", "required": true},
      "stainingDate": {"type": "date", "label": "Date", "required": true}
    }
  },
  "nextPage": "Microscopy & Diagnosis"
}
